mapper.select:
SELECT COUNT(*)
  FROM v_dc3_point_value_all
 WHERE create_time >= #{from}
   AND create_time <  #{to}
   AND (#{tenantId} IS NULL OR tenant_id = #{tenantId})

SELECT ${dimension} AS entity_id,
       COUNT(*)     AS count
  FROM v_dc3_point_value_all
 WHERE create_time >= #{from}
   AND create_time <  #{to}
   AND (#{tenantId} IS NULL OR tenant_id = #{tenantId})
 GROUP BY ${dimension}
 ORDER BY count DESC
 LIMIT #{limit}
